203→export function createInitialEditorState(activeFloorId = null) {
204→  const modelViewport = getInitialModelViewport();
205→  const sheetViewport = getInitialSheetViewport();
206→  return {
207→    activeTool: TOOLS.SELECT,
208→    selectedId: null,
209→    selectedType: null,
210→    toolState: {},
211→    workspaceMode: 'model',
212→    viewport: { ...modelViewport },
213→    modelViewport,
214→    sheetViewport,
215→    showGrid: true,
216→    snapEnabled: true,
217→    viewMode: 'plan',
218→    activeFloorId,
219→    activeSheetId: null,
220→    activeSectionCutId: null,
221→    statusMessage: null,
222→    regionSelection: null,
223→    pastePreview: { active: false, point: null },
224→    maximizedPanel: null,
225→  };
226→}
